62	    }
63	    if let Expr::FnCall { name, args, .. } = expr
64	        && let Some(result) = eval_analysis_helper(name, args, env, trace)
65	    {
66	        return result.map(Value::Str);
67	    }
68	    let (op_name, inputs, result) = match expr {
69	        Expr::IntLit(n, _) => ("literal", vec![], DenseArray::from_scalar(*n as f64)),
70	        Expr::FloatLit(f, _) => ("literal", vec![], DenseArray::from_scalar(*f)),
71	        Expr::StrLit(_, _) => unreachable!(),
72	        Expr::Ident(name, _) => {
73	            let r = env
74	                .get(name)
75	                .cloned()
76	                .ok_or_else(|| EvalError::UndefinedVariable(name.clone()))?;
77	            ("ident", vec![], r)
78	        }
79	        Expr::ArrayLit(elems, _) => ("array_lit", vec![], eval_array_lit(elems, env, trace)?),
80	        Expr::UnaryNeg { operand, .. } => {
