1	//! Evaluation helpers for binops, function calls, and array literals.
2	
3	use mlpl_array::{DenseArray, Shape};
4	use mlpl_parser::{BinOpKind, Expr};
5	use mlpl_trace::{Trace, TraceValue};
6	
7	use crate::env::Environment;
8	use crate::error::EvalError;
9	use crate::eval::eval_expr;
10	use crate::value::Value;
11	
12	pub(crate) fn eval_binop(
13	    op: &BinOpKind,
14	    lhs: &Expr,
15	    rhs: &Expr,
16	    env: &mut Environment,
17	    trace: &mut Option<&mut Trace>,
18	) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
19	    let l = eval_expr(lhs, env, trace)?.into_array()?;
20	    let r = eval_expr(rhs, env, trace)?.into_array()?;
21	    let (name, f): (&str, fn(f64, f64) -> f64) = match op {
22	        BinOpKind::Add => ("add", |a, b| a + b),
23	        BinOpKind::Sub => ("sub", |a, b| a - b),
24	        BinOpKind::Mul => ("mul", |a, b| a * b),
25	        BinOpKind::Div => ("div", |a, b| a / b),
26	    };
27	    let inputs = vec![TraceValue::from_array(&l), TraceValue::from_array(&r)];
28	    let result = l.apply_binop(&r, f)?;
29	    Ok((name, inputs, result))
30	}
31	
32	pub(crate) fn eval_fncall(
33	    name: &str,
34	    args: &[Expr],
35	    env: &mut Environment,
36	    trace: &mut Option<&mut Trace>,
37	) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
38	    let evaluated: Vec<DenseArray> = args
39	        .iter()
40	        .map(|a| eval_expr(a, env, trace).and_then(Value::into_array))
41	        .collect::<Result<Vec<_>, _>>()?;
42	    let inputs: Vec<TraceValue> = evaluated.iter().map(TraceValue::from_array).collect();
43	    let result = mlpl_runtime::call_builtin(name, evaluated)?;
44	    Ok(("fncall", inputs, result))
45	}
46	
47	pub(crate) fn eval_svg(
48	    args: &[Expr],
49	    env: &mut Environment,
50	    trace: &mut Option<&mut Trace>,
51	) -> Result<String, EvalError> {
52	    if args.len() != 2 && args.len() != 3 {
53	        return Err(EvalError::BadArity {
54	            func: "svg".into(),
55	            expected: 2,
56	            got: args.len(),
57	        });
58	    }
59	    let data = eval_expr(&args[0], env, trace)?.into_array()?;
60	    let type_name = match eval_expr(&args[1], env, trace)? {
61	        Value::Str(s) => s,
