            Ok(eval_tensor_expr(&args[0], env, tape, params)?.relu())
        }
        "tanh" => {
            expect_arity(1)?;
            Ok(eval_tensor_expr(&args[0], env, tape, params)?.tanh())
        }
        "sigmoid" => {
            expect_arity(1)?;
            Ok(eval_tensor_expr(&args[0], env, tape, params)?.sigmoid())
        }
        "softmax" => {
            expect_arity(1)?;
            Ok(eval_tensor_expr(&args[0], env, tape, params)?.softmax())
        }
        "transpose" => {
            expect_arity(1)?;
            Ok(eval_tensor_expr(&args[0], env, tape, params)?.transpose())
